    </style>
</head>
<body>
    <header>
        <h1>⚡ WastedToken Mint</h1>
        <p class="tagline">Collectible Physical Challenge Coins</p>
    </header>

    <section class="hero-section">
        <canvas id="coin-hero"></canvas>
    </section>

    <section class="about-section">
        <h2>About WastedToken Mint</h2>
        <p>
            Since 2024, WastedToken Mint has been crafting the finest physical challenge coins for collectors, gamers, and decentralized enthusiasts worldwide. Each coin is minted with precision, featuring exclusive designs and premium finishes.
        </p>
        <p>
            Our coins combine the timeless appeal of numismatic art with digital-age symbolism, creating collectibles that bridge tradition and innovation. Whether you're a serious collector or looking for a unique gift, WastedToken Mint delivers uncompromising quality.
        </p>
    </section>

    <section class="editions-section">
        <h2>Editions</h2>
        <div class="editions-grid">
            <div class="edition" data-edition="bronze" data-state="available">
                <canvas class="edition-canvas"></canvas>
                <h3>Bronze Edition</h3>
                <div class="edition-name">Classic Finish</div>
                <div class="edition-status">Available Now</div>
                <button class="buy">Add to Cart</button>
            </div>

            <div class="edition" data-edition="silver" data-state="available">
                <canvas class="edition-canvas"></canvas>
                <h3>Silver Edition</h3>
                <div class="edition-name">Mirror Finish</div>
                <div class="edition-status">Available Now</div>
                <button class="buy">Add to Cart</button>
            </div>

            <div class="edition" data-edition="gold" data-state="sold-out">
                <canvas class="edition-canvas"></canvas>
                <h3>Gold Edition</h3>
                <div class="edition-name">Prestige Finish</div>
                <div class="edition-status">SOLD OUT</div>
                <button class="buy" disabled>Sold Out</button>
            </div>

            <div class="edition" data-edition="black" data-state="coming-soon">
                <canvas class="edition-canvas"></canvas>
                <h3>Obsidian Edition</h3>
                <div class="edition-name">Matte Black Finish</div>
                <div class="edition-status">Minting Spring 2026</div>
                <button class="buy" disabled>Coming Soon</button>
            </div>
        </div>
    </section>

    <footer>
        <p>&copy; 2026 WastedToken Mint. All rights reserved.</p>
    </footer>

    <script>
        const rotateX = (v, a) => {
            const c = Math.cos(a), s = Math.sin(a);
            return [v[0], v[1] * c - v[2] * s, v[1] * s + v[2] * c];
        };

        const rotateY = (v, a) => {
            const c = Math.cos(a), s = Math.sin(a);
            return [v[0] * c + v[2] * s, v[1], -v[0] * s + v[2] * c];
        };

        const renderCoin = (ctx, time, metalColor) => {
            const w = ctx.canvas.width;
            const h = ctx.canvas.height;

            const grad = ctx.createRadialGradient(w / 2, h / 2, 0, w / 2, h / 2, Math.max(w, h) / 2);
            grad.addColorStop(0, '#2a2a3e');
            grad.addColorStop(1, '#0f0f0f');
            ctx.fillStyle = grad;
            ctx.fillRect(0, 0, w, h);

            const radius = Math.min(w, h) * 0.28;
            const angleY = time * Math.PI * 2;
            const angleX = Math.sin(time * Math.PI * 2) * 0.7;

            const centerX = w / 2;
            const centerY = h / 2;

            const faceZ = Math.cos(angleY);

            if (Math.abs(Math.cos(angleX)) > 0.3) {
                const metalGrad = ctx.createRadialGradient(
                    centerX - radius * 0.3,
                    centerY - radius * 0.3,
                    radius * 0.05,
                    centerX,
                    centerY,
                    radius
                );

                if (faceZ > 0) {
                    metalGrad.addColorStop(0, '#ffffff');
                    metalGrad.addColorStop(0.3, metalColor);
                    metalGrad.addColorStop(0.8, '#' + Math.max(0, parseInt(metalColor.slice(1), 16) - 0x333333).toString(16).padStart(6, '0'));
                    metalGrad.addColorStop(1, '#000000');

                    ctx.fillStyle = metalGrad;
                    ctx.beginPath();
                    ctx.arc(centerX, centerY, radius, 0, Math.PI * 2);
                    ctx.fill();

                    ctx.fillStyle = '#2a2a2a';
                    ctx.font = 'bold ' + Math.floor(radius * 0.5) + 'px sans-serif';
                    ctx.textAlign = 'center';
                    ctx.textBaseline = 'middle';
                    ctx.fillText('⚡', centerX, centerY - radius * 0.1);

                    ctx.fillStyle = '#4a4a4a';
                    ctx.font = Math.floor(radius * 0.2) + 'px sans-serif';
                    ctx.fillText('WASTED TOKEN', centerX, centerY + radius * 0.28);
                } else {
                    ctx.fillStyle = '#1a1a1a';
                    ctx.beginPath();
                    ctx.arc(centerX, centerY, radius, 0, Math.PI * 2);
                    ctx.fill();

                    ctx.fillStyle = '#555';
                    ctx.font = 'bold ' + Math.floor(radius * 0.38) + 'px sans-serif';
                    ctx.textAlign = 'center';
                    ctx.textBaseline = 'middle';
                    ctx.fillText('10,000', centerX, centerY - radius * 0.12);

                    ctx.font = Math.floor(radius * 0.16) + 'px sans-serif';
                    ctx.fillText('TOKENS', centerX, centerY + radius * 0.15);
                }
            }

            ctx.strokeStyle = 'rgba(200, 200, 200, 0.6)';
            ctx.lineWidth = 1.5;
            for (let i = 0; i < 32; i++) {
                const a = (i / 32) * Math.PI * 2;
                const x1 = centerX + Math.cos(a) * radius * 0.93;
                const y1 = centerY + Math.sin(a) * radius * 0.93;
                const x2 = centerX + Math.cos(a) * radius * 1.08;
                const y2 = centerY + Math.sin(a) * radius * 1.08;
                ctx.beginPath();
                ctx.moveTo(x1, y1);
                ctx.lineTo(x2, y2);
                ctx.stroke();
            }

            const specularStrength = Math.max(0, Math.cos(angleY - Math.PI / 6) * 0.7 + 0.3);
            if (specularStrength > 0.15 && Math.abs(Math.cos(angleX)) > 0.2 && faceZ > 0) {
                const hlX = centerX + Math.cos(angleY - Math.PI / 5) * radius * 0.4;
                const hlY = centerY + Math.sin(angleY - Math.PI / 5) * radius * 0.4 - radius * 0.3;

                const hlGrad = ctx.createRadialGradient(hlX, hlY, 0, hlX, hlY, radius * 0.25);
                hlGrad.addColorStop(0, `rgba(255, 255, 255, ${specularStrength * 0.7})`);
                hlGrad.addColorStop(0.4, `rgba(255, 255, 255, ${specularStrength * 0.3})`);
                hlGrad.addColorStop(1, 'rgba(255, 255, 255, 0)');

                ctx.fillStyle = hlGrad;
                ctx.beginPath();
                ctx.arc(hlX, hlY, radius * 0.25, 0, Math.PI * 2);
                ctx.fill();
            }

            const edgeGrad = ctx.createRadialGradient(
                centerX, centerY, radius * 0.8,
                centerX, centerY, radius
            );
            edgeGrad.addColorStop(0, 'rgba(0, 0, 0, 0)');
            edgeGrad.addColorStop(1, 'rgba(0, 0, 0, 0.4)');
            ctx.fillStyle = edgeGrad;
            ctx.beginPath();
            ctx.arc(centerX, centerY, radius, 0, Math.PI * 2);
            ctx.fill();
        };

        const heroCanvas = document.getElementById('coin-hero');
        const heroCtx = heroCanvas.getContext('2d');

        const resizeCanvas = (canvas) => {
            const rect = canvas.getBoundingClientRect();
            canvas.width = rect.width;
            canvas.height = rect.height;
        };

        resizeCanvas(heroCanvas);
        window.addEventListener('resize', () => resizeCanvas(heroCanvas));

        let animationId;
        let currentTime = 0;
        let paused = false;

        const animate = () => {
            if (!paused) {
                currentTime = (currentTime + 1 / 60) % 1;
            }
            renderCoin(heroCtx, currentTime, '#c0a060');
            animationId = requestAnimationFrame(animate);
        };

        animate();

        window.demo = {
            canvas: heroCanvas,
            setTime: (t) => {
                currentTime = t % 1;
                renderCoin(heroCtx, currentTime, '#c0a060');
            },
            pause: () => {
                paused = true;
            }
        };

        const editionCanvases = document.querySelectorAll('.edition-canvas');
        const metalColors = {
            'bronze': '#8b6914',
            'silver': '#c0c0c0',
            'gold': '#ffd700',
            'black': '#2a2a2a'
        };

        editionCanvases.forEach((canvas) => {
            resizeCanvas(canvas);
            const edition = canvas.closest('.edition').getAttribute('data-edition');
            const color = metalColors[edition] || '#c0a060';

            const render = () => {
                renderCoin(canvas.getContext('2d'), 0.15, color);
            };

            render();
            window.addEventListener('resize', render);
        });

        document.querySelectorAll('.buy').forEach(btn => {
            btn.addEventListener('click', () => {
                if (!btn.disabled) {
                    alert('Added to cart! (This is a demo)');
                }
            });
        });
    </script>
</body>
</html>
